// PROCESS: expects msg.payload as an object (after JSON node)

// ---------- 1) Normalize input payload ----------
var p = msg.payload || {};

// free slots (0..3)
var free = Number(p.free);
if (isNaN(free)) free = 0;
if (free < 0) free = 0;
if (free > 3) free = 3;

// occupied slots (0..3)
var occ = 3 - free;
if (occ < 0) occ = 0;
if (occ > 3) occ = 3;

// timestamp (ms)
var ts = Date.now();

// slots as bitstring (e.g., 110)
var slotsStr = "";
if (Array.isArray(p.slots)) {
    slotsStr = String(p.slots.join(""));
}

// entrance / exit events (0/1)
var ent = Number(p.entrance);
if (isNaN(ent)) ent = 0;

var ex = Number(p.exit);
if (isNaN(ex)) ex = 0;

// barrier state
var bar = (p.barrier !== undefined) ? String(p.barrier) : "UNKNOWN";

// topic for classification and traceability
var topic = msg.topic || "";

// ---------- 2) Scenario classification (LOCKED by topic names) ----------
var scenario = "UNKNOWN";
if (topic.indexOf("slots-sim-nonsec") >= 0) scenario = "S1";
else if (topic.indexOf("slots-sim-sec") >= 0) scenario = "S2";
else if (topic.indexOf("slots-hw-nonsec") >= 0) scenario = "S3";
else if (topic.indexOf("slots-hw-sec") >= 0) scenario = "S4";

// Security mode label
var modeText = "UNKNOWN";
if (scenario === "S1" || scenario === "S3") modeText = "NON-SECURE";
else if (scenario === "S2" || scenario === "S4") modeText = "SECURE (TLS)";

// utilization (0..1)
var util = occ / 3;

// ---------- 3) AI latency (ms) from inference branch ----------
// Latency is produced in the HTTP response path and stored in flow context.
// Attach it only if it is "fresh" (e.g., within the last 5 seconds).

var ai_latency = -1;  // IMPORTANT: default value when inference did not occur

var lastLat = flow.get("last_ai_latency_ms");
var lastTs = flow.get("last_ai_latency_ts");

if (lastLat !== undefined && lastLat !== null && lastTs !== undefined) {
    var age = Date.now() - Number(lastTs);
    if (!isNaN(age) && age >= 0 && age <= 5000) {   // 5s freshness window
        ai_latency = Number(lastLat);
        if (isNaN(ai_latency)) ai_latency = -1;
    }
}

// ---------- 4) Attach meta object (dashboard + switch + logging) ----------
// CSV schema (LOCKED):
// epoch_ms,slots_bits,occ,free,entrance_event,exit_event,barrier,ai_latency_ms,scenario,mode,topic
var csvRow =
    ts + "," +
    slotsStr + "," +
    occ + "," +
    free + "," +
    ent + "," +
    ex + "," +
    bar + "," +
    ai_latency + "," +
    scenario + "," +
    modeText + "," +
    topic;

msg.meta = {
    scenario: scenario,
    mode: modeText,
    free: free,
    occ: occ,
    util: util,
    ai_latency_ms: ai_latency,
    csv: csvRow
};

// Keep these for any existing UI nodes that use msg.free/msg.occ/msg.util
msg.free = free;
msg.occ = occ;
msg.util = util;

// Do NOT overwrite msg.payload (preserves downstream compatibility)

// ---------- 5) Build Azure features (DETERMINISTIC, demo-stable) ----------
// Model expects 6 features:
// slot{i}_occupied_ratio, slot{i}_event_rate

var slotsArr = Array.isArray(p.slots) ? p.slots : [1, 1, 0]; // 1=FREE, 0=OCCUPIED

function occ01(v) { return (Number(v) === 0) ? 1 : 0; } // occupied -> 1

var o1 = occ01(slotsArr[0]);
var o2 = occ01(slotsArr[1]);
var o3 = occ01(slotsArr[2]);

// Use entrance/exit events as activity signals (0/1)
var e1 = ent;                 // entrance event
var e2 = ex;                  // exit event
var e3 = (ent || ex) ? 1 : 0; // any event

msg.features = {
    slot1_occupied_ratio: o1,
    slot2_occupied_ratio: o2,
    slot3_occupied_ratio: o3,
    slot1_event_rate: e1,
    slot2_event_rate: e2,
    slot3_event_rate: e3
};
return msg;

msg.topic = "occupied";
msg.payload = Number(msg.occ ?? (3 - (msg.payload?.free ?? 0)));
return msg;

// Build Azure Request for deployed model expecting 6 features:
// slot{i}_occupied_ratio, slot{i}_event_rate

msg.meta = msg.meta || {};
const slots = (msg.payload && Array.isArray(msg.payload.slots)) ? msg.payload.slots : [0,0,0];

// ---- Sliding window state (per slot) ----
const W = 10; // window length (samples). keep small to reduce complexity.
let hist = flow.get("slot_hist") || [[],[],[]];
let last = flow.get("slot_last") || [null,null,null];
let flips = flow.get("slot_flips") || [0,0,0];

for (let i=0; i<3; i++){
  /// slots: 1=FREE, 0=OCCUPIED  -> occupied flag must be inverted
  const v = (Number(slots[i]) === 1) ? 0 : 1;   // 1 = occupiedUPIED

  // update flips counter
  if (last[i] !== null && v !== last[i]) flips[i] += 1;
  last[i] = v;

  // update history
  hist[i].push(v);
  if (hist[i].length > W) hist[i].shift();
}

// store back
flow.set("slot_hist", hist);
flow.set("slot_last", last);
flow.set("slot_flips", flips);

// occupied ratio per slot = mean of window
function mean(arr){
  if (!arr || arr.length === 0) return 0;
  return arr.reduce((a,b)=>a+b,0)/arr.length;
}
const r1 = Number(mean(hist[0]).toFixed(3));
const r2 = Number(mean(hist[1]).toFixed(3));
const r3 = Number(mean(hist[2]).toFixed(3));

// event rate: flips per second (approx). Reset every second using timestamps.
const now = Date.now();
const t_prev = flow.get("flip_t0") || now;
let dt = (now - t_prev)/1000;
if (dt <= 0) dt = 1;

let er1 = 0, er2 = 0, er3 = 0;
if (dt >= 1.0) {
  er1 = Number((flips[0]/dt).toFixed(3));
  er2 = Number((flips[1]/dt).toFixed(3));
  er3 = Number((flips[2]/dt).toFixed(3));

  // reset counter for next window
  flow.set("flip_t0", now);
  flow.set("slot_flips", [0,0,0]);
}

// Final features exactly as API expects
  msg.features = {
    slot1_occupied_ratio: r1,
    slot2_occupied_ratio: r2,
    slot3_occupied_ratio: r3,
    slot1_event_rate: er1,
    slot2_event_rate: er2,
    slot3_event_rate: er3
  };
// Build Azure request using features created in PROCESS (msg.features)
msg.payload = { features: msg.features };

// Build request body exactly as FastAPI expects
msg.headers = msg.headers || {};
msg.headers["Content-Type"] = "application/json";

// If you already have msg.features somewhere, adapt accordingly
const f = msg.features || msg.payload?.features || msg.payload || {};

// Ensure payload is {features:{...}}
msg.payload = { features: f };
return msg;

// Handle Azure Response (LOCKED)
// Parses Azure response, sets msg.ai.prediction consistently, never redeclares variables.

let r = msg.payload;

// Parse if needed
if (typeof r === "string") {
    try { r = JSON.parse(r); } catch(e) { r = {}; }
}
if (!r || typeof r !== "object") r = {};

msg.ai = msg.ai || {};

// If API returns {"detail":"Not Found"} or validation error
if (r.detail) {
    msg.ai.prediction = "AI_ERR";
    msg.ai.recommendation = "Cloud AI unavailable. Using sensor-only status.";
    msg.ai.raw = r;
    return msg;
}

// Normal success path
msg.ai.prediction = (r.prediction !== undefined) ? String(r.prediction).toUpperCase() : "UNKNOWN";
msg.ai.probabilities = r.probabilities || {};
msg.ai.utilization = (r.utilization !== undefined) ? r.utilization : undefined;
msg.ai.raw = r;

return msg;

// Prediction / AI behavior log (NOT timing)

const s = msg.azure_summary || {};
const now = new Date().toISOString();

// CSV columns:
// timestamp, lot_id, total_free, total_occupied, slots_count,
// utilization_pct, status, recommendation
const line = [
  now,
  s.lot_id ?? "",
  s.total_free ?? "",
  s.total_occupied ?? "",
  s.slots_count ?? "",
  s.utilization_pct ?? "",
  s.status ?? "",
  '"' + String(s.recommendation ?? "").replace(/"/g, '""') + '"'
].join(",") + "\n";

msg.payload = line;
return msg;

// Append-only training row for the SAME 6 features Azure expects

const f = msg.features || {};
const util = Number(msg.util ?? msg.meta?.util ?? 0);

// label from utilization (your rule)
let label = "NORMAL";
if (util >= 0.8) label = "CRITICAL";
else if (util >= 0.5) label = "BUSY";

// CSV columns in order expected by retrain script
// timestamp, slot1_occ_ratio, slot2_occ_ratio, slot3_occ_ratio, slot1_event_rate, slot2_event_rate, slot3_event_rate, label
msg.payload = [
  new Date().toISOString(),
  Number(f.slot1_occupied_ratio ?? 0),
  Number(f.slot2_occupied_ratio ?? 0),
  Number(f.slot3_occupied_ratio ?? 0),
  Number(f.slot1_event_rate ?? 0),
  Number(f.slot2_event_rate ?? 0),
  Number(f.slot3_event_rate ?? 0),
  label
].join(",") + "\n";

return msg;

msg.meta = msg.meta || {};
msg.meta.t0 = Date.now(); // start time in ms

const t = (msg.topic || "").toLowerCase();
if (t.includes("nonsec")) msg.meta.mode = "nonsecure";
else if (t.includes("sec")) msg.meta.mode = "secure";
else msg.meta.mode = "unknown";
return msg;

// Ground-truth snapshot
msg.meta.gt_occ = (typeof msg.occ === "number") ? msg.occ : null;
msg.meta.gt_free = (typeof msg.free === "number") ? msg.free : null;

msg.meta.run_id = flow.get("run_id") || ("run_" + new Date().toISOString().slice(0, 10));

return msg;

// Stop Timer + Build Log Record (AFTER HTTP response)

msg.meta = msg.meta || {};
msg.meta.t1 = Date.now();
msg.meta.latency_ms = (msg.meta.t0) ? (msg.meta.t1 - msg.meta.t0) : null;

// Normalize name used by metrics logger
msg.meta.ai_latency_ms = msg.meta.latency_ms;

// Store latest AI latency globally for metrics CSV
flow.set("last_ai_latency_ms", msg.meta.ai_latency_ms);
flow.set("last_ai_latency_ts", Date.now());

const ts = new Date(msg.meta.t1).toISOString();

// HTTP status
const sc = msg.statusCode || "";

// Response JSON from Azure
const resp = msg.payload || {};

// Adapt these keys to your FastAPI response
const prediction = (resp.prediction !== undefined) ? resp.prediction : "";
const probs = (resp.probabilities !== undefined) ? JSON.stringify(resp.probabilities) : "";
const recommendation = (resp.recommendation !== undefined) ? String(resp.recommendation) : "";

// (A) Inference timing CSV (optional, separate log file)
msg.ai_inference_csv = [
  ts,
  msg.meta.run_id || "",
  msg.meta.mode || "",
  sc,
  msg.meta.latency_ms ?? "",
  msg.meta.gt_occ ?? "",
  msg.meta.gt_free ?? "",
  prediction
].join(",");

// (B) Prediction CSV (optional)
msg.ai_prediction_csv = [
  ts,
  msg.meta.run_id || "",
  msg.meta.mode || "",
  prediction,
  '"' + recommendation.replace(/"/g,'""') + '"',
  '"' + probs.replace(/"/g,'""') + '"'
].join(",");

// End-to-End latency
if (msg.meta.e2e_t0) {
  msg.meta.e2e_latency_ms = msg.meta.t1 - msg.meta.e2e_t0;
} else {
  msg.meta.e2e_latency_ms = null;
}

return msg;

msg.headers = msg.headers || {};
msg.headers["Content-Type"] = "application/json";
msg.headers["x-api-key"] = "StrongPass123";
return msg;

msg.debug_line = {
  statusCode: msg.statusCode,
  responseUrl: msg.responseUrl,
  payload: msg.payload
};
return msg;

const t = msg.topic || "";

let scenario = "UNK";
if (t.includes("sim-nonsec")) scenario = "S1";
else if (t.includes("sim-sec")) scenario = "S2";
else if (t.includes("hw-nonsec")) scenario = "S3";
else if (t.includes("hw-sec")) scenario = "S4";

msg.meta = msg.meta || {};
msg.meta.scenario = scenario;
msg.meta.mode = (scenario === "S2" || scenario === "S4") ? "SECURE (TLS)" : "NON-SECURE";

return msg;

const active = flow.get("activeScenario") || "ALL";
const s = (msg.meta && msg.meta.scenario) ? msg.meta.scenario : "UNK";

// show live status so we know gate is receiving messages
node.status({fill:"blue",shape:"dot",text:`active=${active} got=${s}`});

// If you want to *debug* without dropping anything, set PASS_ALL=true
const PASS_ALL = false;

if (!PASS_ALL) {
  if (active !== "ALL" && s !== active) return null;
}

return msg;

// Expect msg.payload to be like: "S1", "S2", "S3", "S4", or "ALL"
// If your inject nodes are not sending that yet, fix inject payload (next step).

const s = String(msg.payload || "ALL").trim().toUpperCase();

flow.set("activeScenario", s);

// show selected scenario on the node (helps debugging)
node.status({fill:"green", shape:"dot", text:`activeScenario=${s}`});

// IMPORTANT: do not forward this message to any file/log nodes
return null;

const occ = 3 - Number(msg.payload.free);
msg.payload = (occ / 3) * 100;
return msg;

// Prefer topic-based detection (most reliable)
// Fallback to meta/payload if topic doesn't encode it

const topic = (msg.topic || "").toLowerCase();
const metaMode = (msg.meta?.mode || "").toString().toLowerCase();
const payloadMode = (msg.payload?.mode || msg.payload?.security || "").toString().toLowerCase();

function isSecure(s) {
    return s.includes("sec") && !s.includes("non");
}
function isNonSecure(s) {
    return s.includes("non") || s.includes("plain") || s.includes("1883");
}

// 1) Detect from topic (preferred)
let secure = false;
let nonsecure = false;

if (topic) {
    secure = isSecure(topic);
    nonsecure = isNonSecure(topic) || topic.includes("nonsec") || topic.includes("non-sec");
}

// 2) Fallback to meta/payload
if (!secure && !nonsecure) {
    secure = isSecure(metaMode) || isSecure(payloadMode);
    nonsecure = isNonSecure(metaMode) || isNonSecure(payloadMode);
}

// 3) Format output
if (secure) {
    msg.payload = "🔒 SECURE (TLS)";
} else if (nonsecure) {
    msg.payload = "🔓 NON-SECURE";
} else {
    msg.payload = "UNKNOWN";
}

return msg;

const now = Date.now();
const sec = Math.floor(now / 1000);
const scenario = msg.meta?.scenario || "UNK";
const key = scenario + ":" + sec;

const lastKey = flow.get("tp_key");
let count = flow.get("tp_count") || 0;

// new second started
if (key !== lastKey) {
  // before reset, log the previous second if it exists
  const prevScenario = (lastKey || "").split(":")[0];
  const prevSec = parseInt((lastKey || "0:0").split(":")[1] || "0", 10);
  const prevCount = count;

  flow.set("tp_key", key);
  flow.set("tp_count", 1);
  msg.tp_mps = 1;

  // emit log for previous second (skip first time)
  if (lastKey) {
    const ts = new Date(prevSec * 1000).toISOString();
    const deployment = (prevScenario === "S1" || prevScenario === "S2") ? "simulation" : "hardware";
    const security = (prevScenario === "S2" || prevScenario === "S4") ? "tls" : "nonsec";

    const logMsg = {
      payload: {
        timestamp: ts,
        scenario: prevScenario,
        deployment,
        security,
        msg_rate: prevCount
      }
    };
    return [msg, logMsg];
  }
  return [msg, null];
}

// same second continues
count += 1;
flow.set("tp_count", count);
msg.tp_mps = count;
return [msg, null];

// Build a friendly label for dashboard (still keep S1..S4 for experiments)
const s = msg.meta?.scenario || "UNK";

let label = "UNKNOWN";
if (s === "S1") label = "S1 (SIM, NON-SECURE)";
else if (s === "S2") label = "S2 (SIM, SECURE/TLS)";
else if (s === "S3") label = "S3 (HW, NON-SECURE)";
else if (s === "S4") label = "S4 (HW, SECURE/TLS)";
else if (s === "ALL") label = "ALL (no gating)";

msg.payload = label;
return msg;

const s = msg.meta?.scenario || "UNK";
const isSecure = (s === "S2" || s === "S4");

if (!isSecure) {
  msg.payload = "TLS: OFF (no certificate)";
  return msg;
}

// Use accurate wording: CA is used by the MQTT client when TLS is enabled
msg.payload = "TLS: ON (CA certificate configured)";
return msg;


const scenario = msg.meta?.scenario || "UNK";

let text = "TLS: UNKNOWN";

if (scenario === "S1" || scenario === "S3") {
    text = "TLS: OFF (no certificate)";
}
else if (scenario === "S2" || scenario === "S4") {
    text = "TLS: ON (CA certificate configured)";
}

msg.payload = text;
return msg;

const scenario = msg.meta?.scenario || "UNK";

let text = "Port: UNKNOWN";

if (scenario === "S1" || scenario === "S3") {
    text = "Port: 1883 (MQTT)";
}
else if (scenario === "S2" || scenario === "S4") {
    text = "Port: 8883 (MQTT over TLS)";
}

msg.payload = text;
return msg;

// All CSV file function (S1–S4 router)
// Purpose:
//  - ensure msg.meta.csv exists (created in PROCESS)
//  - route each message to exactly one output based on msg.meta.scenario
//  - set msg.payload to the CSV line for File nodes

if (!msg.meta || !msg.meta.csv) return [null, null, null, null];

var sc = (msg.meta.scenario !== undefined) ? String(msg.meta.scenario).trim() : "UNKNOWN";

// payload must be the line written by File node
msg.payload = msg.meta.csv;

// Route to one output only
switch (sc) {
    case "S1":
        return [msg, null, null, null];
    case "S2":
        return [null, msg, null, null];
    case "S3":
        return [null, null, msg, null];
    case "S4":
        return [null, null, null, msg];
    default:
        // Unknown scenario -> drop (or route to S1 if you want, but dropping is cleaner)
        return [null, null, null, null];
}

// AI Latency Tap: writes AI latency into flow context for metrics CSV.
// Non-invasive: does not modify msg.payload or msg.meta required by dashboard.

try {
    const lat = (msg.meta && msg.meta.latency_ms !== undefined) ? Number(msg.meta.latency_ms) : null;

    if (lat !== null && !isNaN(lat) && lat >= 0) {
        flow.set("last_ai_latency_ms", lat);
        flow.set("last_ai_latency_ts", (msg.meta && msg.meta.t1) ? msg.meta.t1 : Date.now());
    }
    } catch (e) {}

return msg;

const pred = (msg.ai && msg.ai.prediction) ? String(msg.ai.prediction).toUpperCase() : "UNKNOWN";

let rec = "";
if (pred === "NORMAL") rec = "Parking available. Normal traffic.";
else if (pred === "BUSY") rec = "Moderate congestion. Consider alternate slot/entry.";
else if (pred === "CRITICAL") rec = "Lot near/full. Redirect to nearest parking.";
else rec = "AI unavailable. Using sensor-only status.";

msg.ai = msg.ai || {};
msg.ai.recommendation = rec;
return msg;

// Expect msg.payload is an object (already parsed JSON)
const p = msg.payload || {};
msg.payload = p.barrier || "UNKNOWN";
return msg;

msg.meta = msg.meta || {};
msg.meta.e2e_t0 = Date.now();

// capture scenario once
msg.meta.scenario = msg.meta.scenario || flow.get("active_scenario") || "UNK";

return msg;

const ts = new Date().toISOString();
const scenario = msg.meta?.scenario || flow.get("active_scenario") || "UNK";

// Optional tags (keep consistent with your chapter tables)
const deployment = scenario.startsWith("S1") || scenario.startsWith("S2") ? "simulation" : "hardware";
const security   = (msg.meta?.mode || "").includes("sec") ? "tls" : "nonsec";

const rate = msg.tp_mps ?? msg.payload ?? 0;

msg.payload = [ts, scenario, deployment, security, rate].join(",") + "\n";
return msg;

const ts = new Date().toISOString();
const scenario = flow.get("activeScenario") || "ALL";

// stdout from exec should be "cpu,mem"
const out = (msg.payload || "").toString().trim();
if (!out.includes(",")) return null;

msg.payload = `${ts},${scenario},${out}`;   // file node appends newline
return msg;

// Stop E2E timer and build CSV line WITHOUT touching msg.payload

msg.meta = msg.meta || {};
msg.meta.e2e_t1 = Date.now();

const ts = new Date(msg.meta.e2e_t1).toISOString();
const e2e_ms = msg.meta.e2e_t0 ? (msg.meta.e2e_t1 - msg.meta.e2e_t0) : "";

// Use your existing fields (adjust only if you used different naming)
const run_id   = msg.meta.run_id || flow.get("run_id") || "";
const scenario = msg.meta.scenario || flow.get("active_scenario") || "UNK";
const mode     = msg.meta.mode || "unknown";

// AI-only latency if available (C3)
const ai_ms = (msg.meta.ai_latency_ms !== undefined) ? msg.meta.ai_latency_ms : (flow.get("last_ai_latency_ms") ?? "");

// store CSV line in a side field
msg.e2e_csv_line = [ts, run_id, scenario, mode, e2e_ms, ai_ms].join(",") + "\n";

return msg;

// AI Hold + Worst-Across-Streams (LOCKED)
// - Never returns null (so UI cannot be overwritten by other paths)
// - Holds worst label for HOLD_MS even if later NORMAL arrives
// - Works across multiple topics (sim/hw, sec/nonsec)

const HOLD_MS = 30000; // 30s (stable). You can reduce later to 15000.
const sev = { NORMAL: 0, BUSY: 1, CRITICAL: 2 };
const now = Date.now();

// Read incoming prediction if present
const incomingRaw = (msg.ai?.prediction ?? msg.payload?.prediction ?? null);
const incoming = incomingRaw ? String(incomingRaw).toUpperCase() : null;

// Load hold state
let held = flow.get("ai_held_label") || "NORMAL";
let heldTs = flow.get("ai_held_ts") || 0;

// Update hold state only if incoming is valid label
if (incoming && (incoming in sev)) {
  // If upgrade or same severity -> accept immediately and reset timer
  if (sev[incoming] >= sev[held]) {
    held = incoming;
    heldTs = now;
  } else {
    // downgrade only if hold time expired
    if ((now - heldTs) >= HOLD_MS) {
      held = incoming;
      heldTs = now;
    }
  }
}

// Persist hold state
flow.set("ai_held_label", held);
flow.set("ai_held_ts", heldTs);

// FORCE outgoing prediction to held label (always)
msg.ai = msg.ai || {};
msg.ai.prediction = held;

// Optional debug fields (won’t affect UI)
msg.ai._incoming = incoming;
msg.ai._held_age_ms = now - heldTs;

return msg;
